public class ChatClient {
    private String username;
    private ChatMediator mediator;
    private ChatClientGUI gui;

    public ChatClient(String username, ChatMediator mediator) {
        this.username = username;
        this.mediator = mediator;
        mediator.registerClient(this);
    }

    public String getUsername() {
        return username;
    }

    public void setGUI(ChatClientGUI gui) {
        this.gui = gui;
    }

    public void sendMessage(String message, String to) {
        String displayMessage = "You to " + to + ": " + message;
        gui.displayMessage(displayMessage);
        mediator.sendMessage(message, username, to);
    }

    public void receiveMessage(String message, String from) {
        String displayMessage = from + " to You: " + message;
        gui.displayMessage(displayMessage);
    }
}

import javafx.geometry.Insets;
import javafx.scene.Scene;
import javafx.scene.control.*;
import javafx.scene.layout.VBox;
import javafx.stage.Stage;

import java.util.List;

public class ChatClientGUI {
    private ChatClient client;
    private ChatServer server;
    private TextArea messageArea;
    private TextField messageField;
    private ComboBox<String> recipientSelector;
    private Button sendButton;

    public ChatClientGUI(ChatClient client, ChatServer server) {
        this.client = client;
        this.server = server;
        client.setGUI(this);
    }

    public void start(Stage stage) {
        stage.setTitle("Chat Client - " + client.getUsername());

        VBox root = new VBox(10);
        root.setPadding(new Insets(10));

        // Message display area
        messageArea = new TextArea();
        messageArea.setEditable(false);
        messageArea.setPrefHeight(300);
        messageArea.setWrapText(true);

        // Recipient selector
        Label recipientLabel = new Label("Select recipient:");
        recipientSelector = new ComboBox<>();
        updateRecipientList();

        // Message input field
        Label messageLabel = new Label("Your message:");
        messageField = new TextField();
        messageField.setPrefWidth(300);

        // Send button
        sendButton = new Button("Send Message");
        sendButton.setOnAction(e -> sendMessage());

        // Allow sending with Enter key
        messageField.setOnAction(e -> sendMessage());

        root.getChildren().addAll(
            messageArea,
            recipientLabel,
            recipientSelector,
            messageLabel,
            messageField,
            sendButton
        );

        Scene scene = new Scene(root, 400, 450);
        stage.setScene(scene);
        stage.show();

        displayMessage("Welcome to the chat, " + client.getUsername() + "!");
    }

    private void updateRecipientList() {
        List<String> allUsers = server.getClientUsernames();
        recipientSelector.getItems().clear();

        for (String username : allUsers) {
            if (!username.equals(client.getUsername())) {
                recipientSelector.getItems().add(username);
            }
        }

        if (!recipientSelector.getItems().isEmpty()) {
            recipientSelector.getSelectionModel().selectFirst();
        }
    }

    private void sendMessage() {
        String message = messageField.getText().trim();
        String recipient = recipientSelector.getValue();

        if (message.isEmpty()) {
            displayMessage("Error: Message cannot be empty");
            return;
        }

        if (recipient == null) {
            displayMessage("Error: Please select a recipient");
            return;
        }

        client.sendMessage(message, recipient);
        messageField.clear();
    }

    public void displayMessage(String message) {
        messageArea.appendText(message + "\n");
    }
}

public interface ChatMediator {
    void registerClient(ChatClient client);
    void sendMessage(String message, String from, String to);
}

import java.util.ArrayList;
import java.util.List;

public class ChatServer implements ChatMediator {
    private List<ChatClient> clients;

    public ChatServer() {
        this.clients = new ArrayList<>();
    }

    @Override
    public void registerClient(ChatClient client) {
        clients.add(client);
        System.out.println("Client registered: " + client.getUsername());
    }

    @Override
    public void sendMessage(String message, String from, String to) {
        System.out.println("Message from " + from + " to " + to + ": " + message);

        for (ChatClient client : clients) {
            if (client.getUsername().equals(to)) {
                client.receiveMessage(message, from);
                break;
            }
        }
    }

    public List<String> getClientUsernames() {
        List<String> usernames = new ArrayList<>();
        for (ChatClient client : clients) {
            usernames.add(client.getUsername());
        }
        return usernames;
    }
}

import javafx.application.Application;
import javafx.stage.Stage;

public class Main extends Application {

    @Override
    public void start(Stage primaryStage) {
        // Create the mediator (chat server)
        ChatServer server = new ChatServer();

        // Create three chat clients
        ChatClient client1 = new ChatClient("Alice", server);
        ChatClient client2 = new ChatClient("Bob", server);
        ChatClient client3 = new ChatClient("Charlie", server);

        // Create GUI for each client
        ChatClientGUI gui1 = new ChatClientGUI(client1, server);
        ChatClientGUI gui2 = new ChatClientGUI(client2, server);
        ChatClientGUI gui3 = new ChatClientGUI(client3, server);

        // Create stages for each client window
        Stage stage1 = new Stage();
        Stage stage2 = new Stage();
        Stage stage3 = new Stage();

        // Position windows
        stage1.setX(100);
        stage1.setY(100);

        stage2.setX(550);
        stage2.setY(100);

        stage3.setX(1000);
        stage3.setY(100);

        // Start each GUI
        gui1.start(stage1);
        gui2.start(stage2);
        gui3.start(stage3);
    }

    public static void main(String[] args) {
        launch(args);
    }
}
